const {
  PERMISSION_MODULES,
  MODULE_ACTION_MAP,
} = require("../constants/permissionModules");

const ACTION_LABELS = {
  yes: "Yes",
  read_user_chat: "Read User Chat",
  continue_chat: "Continue Chat",
  view: "View",
  create: "Create",
  edit: "Edit",
  delete: "Delete",
  manage_stock: "Manage Stock",
  verify: "Verify",
  manage_percentage_charge: "Manage Percentage Charge",
  request_approve: "Approve Requests",
  request_reject: "Reject Requests",
  expire: "Expire",
  approve: "Approve",
  reject: "Reject",
  update: "Update",
};

const isMainAdmin = (user) => user?.role === "admin";

const getModulePermission = (user, module) =>
  user?.permissions?.find((permission) => permission.module === module);

const hasModuleAccess = (user, module) => {
  if (isMainAdmin(user)) {
    return true;
  }

  if (user?.role !== "sub-admin") {
    return false;
  }

  const modulePermission = getModulePermission(user, module);
  return Boolean(modulePermission?.actions?.length);
};

const hasAction = (user, module, action) => {
  if (isMainAdmin(user)) {
    return true;
  }

  if (user?.role !== "sub-admin") {
    return false;
  }

  const modulePermission = getModulePermission(user, module);
  return Boolean(modulePermission?.actions?.includes(action));
};

const getActionLabel = (action) => ACTION_LABELS[action] || action;

module.exports = {
  PERMISSION_MODULES,
  MODULE_ACTION_MAP,
  ACTION_LABELS,
  isMainAdmin,
  getModulePermission,
  hasModuleAccess,
  hasAction,
  getActionLabel,
};
